#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);

my $MINIGIT_DIR = ".minigit";
my $OBJECTS_DIR = "$MINIGIT_DIR/objects";
my $COMMITS_DIR = "$MINIGIT_DIR/commits";
my $INDEX_FILE  = "$MINIGIT_DIR/index";
my $HEAD_FILE   = "$MINIGIT_DIR/HEAD";

sub minihash {
    my ($data) = @_;
    use integer;
    my $h = 1469598103934665603;
    for my $b (unpack("C*", $data)) {
        $h ^= $b;
        $h *= 1099511628211;
    }
    no integer;
    return sprintf("%016x", $h);
}

sub read_file {
    my ($path) = @_;
    open my $fh, '<:raw', $path or return "";
    local $/;
    my $content = <$fh>;
    close $fh;
    return defined $content ? $content : "";
}

sub write_file {
    my ($path, $content) = @_;
    open my $fh, '>:raw', $path or die "Cannot write $path: $!\n";
    print $fh $content;
    close $fh;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path($OBJECTS_DIR);
    make_path($COMMITS_DIR);
    write_file($INDEX_FILE, "");
    write_file($HEAD_FILE, "");
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -e $file) {
        print "File not found\n";
        exit 1;
    }

    my $content = read_file($file);
    my $hash = minihash($content);

    write_file("$OBJECTS_DIR/$hash", $content);

    # Read current index
    my $index_content = read_file($INDEX_FILE);
    my @lines = grep { $_ ne '' } split /\n/, $index_content;

    # Add if not already present
    unless (grep { $_ eq $file } @lines) {
        push @lines, $file;
        write_file($INDEX_FILE, join("\n", @lines) . "\n");
    }
}

sub cmd_commit {
    my ($message) = @_;

    my $index_content = read_file($INDEX_FILE);
    my @files = grep { $_ ne '' } split /\n/, $index_content;

    if (!@files) {
        print "Nothing to commit\n";
        exit 1;
    }

    @files = sort @files;

    my $parent = read_file($HEAD_FILE);
    $parent =~ s/\s+$//;
    $parent = "NONE" if $parent eq '';

    my $timestamp = time();

    my @file_entries;
    for my $file (@files) {
        my $content = read_file($file);
        my $hash = minihash($content);
        push @file_entries, "$file $hash";
    }

    my $commit_content = "parent: $parent\n";
    $commit_content .= "timestamp: $timestamp\n";
    $commit_content .= "message: $message\n";
    $commit_content .= "files:\n";
    $commit_content .= join("\n", @file_entries) . "\n";

    my $commit_hash = minihash($commit_content);

    write_file("$COMMITS_DIR/$commit_hash", $commit_content);
    write_file($HEAD_FILE, $commit_hash);
    write_file($INDEX_FILE, "");

    print "Committed $commit_hash\n";
}

sub cmd_log {
    my $head = read_file($HEAD_FILE);
    $head =~ s/\s+$//;

    if ($head eq '') {
        print "No commits\n";
        return;
    }

    my $current = $head;
    my $first = 1;

    while ($current ne '' && $current ne 'NONE') {
        my $commit_path = "$COMMITS_DIR/$current";
        last unless -f $commit_path;

        my $content = read_file($commit_path);
        my ($timestamp, $message, $parent_val);

        for my $line (split /\n/, $content) {
            if ($line =~ /^timestamp: (.+)$/) {
                $timestamp = $1;
            } elsif ($line =~ /^message: (.+)$/) {
                $message = $1;
            } elsif ($line =~ /^parent: (.+)$/) {
                $parent_val = $1;
            }
        }

        print "\n" unless $first;
        print "commit $current\n";
        print "Date: $timestamp\n";
        print "Message: $message\n";

        $first = 0;
        $current = defined $parent_val ? $parent_val : 'NONE';
    }
}

# Main
my $command = shift @ARGV;

if (!defined $command) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($command eq 'init') {
    cmd_init();
} elsif ($command eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($command eq 'commit') {
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    if (!defined $flag || $flag ne '-m' || !defined $message) {
        print "Usage: minigit commit -m \"<message>\"\n";
        exit 1;
    }
    cmd_commit($message);
} elsif ($command eq 'log') {
    cmd_log();
} else {
    print "Unknown command: $command\n";
    exit 1;
}

